.darma-loader-uiverse-gooey-hourglass-drops {
  position: relative;
  width: 1.5em;
  aspect-ratio: 1/2;
  filter: url(#uiverse-gooey-hourglass-drops-goo);
}

#uiverse-gooey-hourglass-drops-goo {
display: none
}

.darma-loader-uiverse-gooey-hourglass-drops:before, .darma-loader-uiverse-gooey-hourglass-drops:after {
content: '';
position: absolute;
inset: 0;
margin: auto;
width: 100%;
aspect-ratio: 1/1;
animation: 1.5s ease-out infinite darma-loader-uiverse-gooey-hourglass-drops-loader;
border-radius: 50%;
}

.darma-loader-uiverse-gooey-hourglass-drops:before {
background: linear-gradient(rgb(255, 206, 58), rgb(66, 181, 73))
}

.darma-loader-uiverse-gooey-hourglass-drops:after {
animation-delay: 0.75s;
background: linear-gradient(to top, rgb(114, 223, 231), rgb(66, 181, 73))
}

@keyframes darma-loader-uiverse-gooey-hourglass-drops-loader {
0%, 50%, 100% {
transform: translateY(0)
}

25% {
transform: translateY(70%)
}

75% {
transform: translateY(-70%)
}
}

